PE-unquoted-service-path.script:
# AUTHORIZED LAB ONLY. Read-only: enumerates service ImagePaths, flags unquoted paths that
# contain a space AND have a writable intermediate directory. Modifies nothing.
$ErrorActionPreference = 'SilentlyContinue'
function Test-WritableDir($dir) {
  try {
    $acl = Get-Acl $dir
    $me  = [System.Security.Principal.WindowsIdentity]::GetCurrent().Groups
    foreach ($r in $acl.Access) {
      if ($r.FileSystemRights -match 'Write|Modify|FullControl' -and $r.AccessControlType -eq 'Allow') {
        if ($me -contains $r.IdentityReference -or $r.IdentityReference -match 'Users|Authenticated|Everyone') { return $true }
      }
    }
  } catch {}
  return $false
}
$vuln = 0
Get-CimInstance Win32_Service | Where-Object { $_.PathName } | ForEach-Object {
  $p = $_.PathName.Trim()
  if ($p -notmatch '^\"' -and $p -match '\.exe' -and ($p.Split(' ')[0] -ne $p) -and $p -match ' ') {
    $exe = ($p -split '\.exe')[0] + '.exe'
    $dirs = @(); $acc = ''
    foreach ($seg in ($exe -split '\\')) { $acc = if ($acc) { "$acc\$seg" } else { $seg }; if (Test-Path $acc -PathType Container) { $dirs += $acc } }
    $writable = $dirs | Where-Object { Test-WritableDir $_ }
    if ($writable) { Write-Host "VULNERABLE  $($_.Name): unquoted '$p' ; writable dir(s): $($writable -join ', ')"; $vuln++ }
    else { Write-Host "review      $($_.Name): unquoted but no writable intermediate dir found" }
  }
}
if ($vuln -eq 0) { Write-Host 'PASS: no exploitable unquoted service paths found' } else { Write-Host "RESULT: VULNERABLE ($vuln service(s))" }

PE-weak-service-file-perms.script:
# AUTHORIZED LAB ONLY. Read-only: for each service binary, checks whether a non-admin principal
# has Write/Modify on the .exe or its folder (would allow binary replacement). No changes made.
$ErrorActionPreference = 'SilentlyContinue'
$weakIds = 'Everyone','BUILTIN\\Users','NT AUTHORITY\\Authenticated Users','BUILTIN\\Authenticated Users'
$flag = 0
Get-CimInstance Win32_Service | Where-Object { $_.PathName } | ForEach-Object {
  $svc = $_.Name
  $exe = ($_.PathName.Trim('\"') -split '\.exe')[0] + '.exe'
  if (-not (Test-Path $exe)) { return }
  foreach ($target in @($exe, (Split-Path $exe))) {
    $acl = Get-Acl $target
    foreach ($r in $acl.Access) {
      if ($r.AccessControlType -eq 'Allow' -and $r.FileSystemRights -match 'Write|Modify|FullControl' -and ($weakIds -contains $r.IdentityReference.Value)) {
        Write-Host "VULNERABLE  $svc : '$($r.IdentityReference.Value)' has $($r.FileSystemRights) on $target"; $flag++
      }
    }
  }
}
if ($flag -eq 0) { Write-Host 'PASS: no weak service-binary permissions found' } else { Write-Host "RESULT: VULNERABLE ($flag finding(s))" }
